import React from "react";
import ReactDOM from "react-dom/client";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import App from "./App"; // Optional if you have a layout component
import HomePage from "./pages/HomePage";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Dashboard from "./pages/Dashboard";
import Profile from "./pages/Profile";
import Notes from "./pages/Notes";
import Notices from "./pages/Notices";
import Events from "./pages/Events";
import Internship from "./pages/Internship";
import Placement from "./pages/Placement";
import Contact from "./pages/Contact";
import AOS from "aos";
import "aos/dist/aos.css";
import "./index.css"; // Your global styles

AOS.init(); // Initialize scroll animations

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <BrowserRouter>
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />
      <Route path="/dashboard" element={<Dashboard />} />
      <Route path="/profile" element={<Profile />} />
      <Route path="/notes" element={<Notes />} />
      <Route path="/notices" element={<Notices />} />
      <Route path="/events" element={<Events />} />
      <Route path="/internship" element={<Internship />} />
      <Route path="/placement" element={<Placement />} />
      <Route path="/contact" element={<Contact />} />
      {/* Optional: Add 404 fallback */}
      <Route path="*" element={<div style={{ textAlign: "center", marginTop: "50px" }}><h2>404 - Page Not Found</h2></div>} />
    </Routes>
  </BrowserRouter>
);
